// Budget Page
import React, { useEffect, useState } from 'react';
import { budgetService, categoryService } from '../services/api';
import './BudgetPage.css';
import { FiEdit2, FiTrash2, FiPlus } from 'react-icons/fi';

/**
 * BudgetPage - Manage budgets
 */
const BudgetPage = () => {
  const [budgets, setBudgets] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    categoryId: '',
    limitAmount: '',
    month: new Date().toISOString().substring(0, 7),
    alertThreshold: '80',
  });

  useEffect(() => {
    fetchBudgets();
    fetchCategories();
  }, []);

  const fetchBudgets = async () => {
    try {
      const response = await budgetService.getCurrentMonth();
      setBudgets(response.data);
    } catch (err) {
      setError('Failed to load budgets');
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const response = await categoryService.getAll();
      setCategories(response.data);
    } catch (err) {
      console.error('Failed to load categories');
    }
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await budgetService.setOrUpdate(formData.categoryId, {
        limitAmount: parseFloat(formData.limitAmount),
        month: formData.month,
        alertThreshold: parseFloat(formData.alertThreshold),
      });
      fetchBudgets();
      resetForm();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save budget');
    }
  };

  const resetForm = () => {
    setFormData({
      categoryId: '',
      limitAmount: '',
      month: new Date().toISOString().substring(0, 7),
      alertThreshold: '80',
    });
    setShowForm(false);
  };

  if (loading) {
    return (
      <div className="loading">
        <div className="spinner"></div>
      </div>
    );
  }

  return (
    <div className="budget-page">
      <div className="page-header">
        <h1>Budget Management</h1>
        <button
          className="btn btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          <FiPlus /> Set Budget
        </button>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      {/* Form */}
      {showForm && (
        <div className="budget-form card">
          <h2>Set Monthly Budget</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Category</label>
                <select
                  name="categoryId"
                  value={formData.categoryId}
                  onChange={handleFormChange}
                  className="form-select"
                  required
                >
                  <option value="">Select Category</option>
                  {categories.map((cat) => (
                    <option key={cat.id} value={cat.id}>
                      {cat.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Budget Limit</label>
                <input
                  type="number"
                  name="limitAmount"
                  value={formData.limitAmount}
                  onChange={handleFormChange}
                  className="form-input"
                  placeholder="0.00"
                  step="0.01"
                  required
                />
              </div>

              <div className="form-group">
                <label className="form-label">Month</label>
                <input
                  type="month"
                  name="month"
                  value={formData.month}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                />
              </div>
            </div>

            <div className="form-group">
              <label className="form-label">Alert Threshold (%)</label>
              <input
                type="number"
                name="alertThreshold"
                value={formData.alertThreshold}
                onChange={handleFormChange}
                className="form-input"
                min="0"
                max="100"
                required
              />
            </div>

            <div className="form-actions">
              <button type="submit" className="btn btn-primary">
                Set Budget
              </button>
              <button type="button" className="btn btn-secondary" onClick={resetForm}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Budgets List */}
      <div className="budgets-grid">
        {budgets.map((budget) => (
          <div key={budget.id} className="budget-card card">
            <div className="budget-header">
              <h3>{budget.categoryName}</h3>
              <span className="badge">{budget.month}</span>
            </div>

            <div className="progress-container">
              <div className="progress-bar">
                <div
                  className={`progress-fill ${
                    budget.usagePercentage > 100 ? 'danger' : ''
                  }`}
                  style={{ width: `${Math.min(100, budget.usagePercentage)}%` }}
                ></div>
              </div>
              <div className="progress-text">
                {budget.usagePercentage.toFixed(1)}%
              </div>
            </div>

            <div className="budget-details">
              <div className="detail-item">
                <span>Limit:</span>
                <strong>${budget.limitAmount.toFixed(2)}</strong>
              </div>
              <div className="detail-item">
                <span>Spent:</span>
                <strong>${budget.spent.toFixed(2)}</strong>
              </div>
              <div className="detail-item">
                <span>Remaining:</span>
                <strong className={budget.remaining >= 0 ? '' : 'danger'}>
                  ${budget.remaining.toFixed(2)}
                </strong>
              </div>
            </div>

            {budget.usagePercentage > 100 && (
              <div className="alert alert-danger">
                Budget exceeded by ${Math.abs(budget.remaining).toFixed(2)}!
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default BudgetPage;
